use std::str::{FromStr};

fn main() {
  let mut r = Read::new();
  let ln = r.many();
  print!("{}", solve(ln[0], ln[1], ln[2]));
}

fn solve(t: i32, l: i32, r: i32) -> i64 {
  let b = 1000000007;
  let mut f = vec![0;(r + 1) as usize];
  for i in 1..r as i64 + 1 {
    for j in 2..r as i64 / i + 1 {
      f[(i * j) as usize] = (f[i as usize] + i * j * (j - 1) / 2) % b;
    }
  }

  f[l as usize..r as usize + 1].iter().fold((0, 1), |(s, p), fi| ((s + p * fi) % b, p * t as i64 % b)).0
}

struct Read { s: String }

impl Read {
  fn new() -> Read {
    Read{s: String::new()}
  }

  #[allow(unused_must_use)]
  fn line(&mut self) -> &str {
    self.s.clear();
    std::io::stdin().read_line(&mut self.s);
    self.s.trim()
  }

  fn one<T: FromStr>(&mut self) -> T where <T as FromStr>::Err: std::fmt::Debug {
    self.line().parse().unwrap()
  }

  fn many<T: FromStr>(&mut self) -> Vec<T> where <T as FromStr>::Err: std::fmt::Debug {
    self.line().split(' ').map(|x| x.parse().unwrap()).collect()
  }
}
